changeSet.sql:
CREATE OR REPLACE FUNCTION NOTARIST.TENANT_ISOLATION_POLICY(
    p_schema IN VARCHAR2,
    p_object IN VARCHAR2
) RETURN VARCHAR2
IS
    v_tenant_id VARCHAR2(64);
    v_system    VARCHAR2(1);
BEGIN
    v_tenant_id := SYS_CONTEXT('NOTARIST_CTX', 'TENANT_ID');

    IF v_tenant_id IS NOT NULL THEN
        -- Reference SYS_CONTEXT in the predicate itself rather than inlining the
        -- literal tenant value: the generated SQL text is then identical for every
        -- session, so Oracle can share one cursor instead of hard-parsing per tenant.
        RETURN 'TENANT_ID = SYS_CONTEXT(''NOTARIST_CTX'', ''TENANT_ID'')';
    END IF;

    v_system := SYS_CONTEXT('NOTARIST_CTX', 'SYSTEM_SESSION');

    IF v_system = 'Y' THEN
        -- Trusted system session: the caller called SET_NOTARIST_CTX.set_system_identity
        -- ON PURPOSE (login lookup, ingestion worker). Unrestricted.
        RETURN '1 = 1';
    END IF;

    -- FAIL CLOSED. No tenant identity and no explicit system exemption means the caller
    -- forgot to establish a VPD context. Returning '1 = 1' here (the original design)
    -- would have made this policy useless for its actual purpose: F7 exists to backstop
    -- a query path that forgets its tenant filter, and fail-open hands that path every
    -- tenant's rows. Show it nothing instead.
    RETURN '1 = 0';
END TENANT_ISOLATION_POLICY;

rollback.sql:
BEGIN
    DBMS_RLS.DROP_POLICY(
        object_schema => 'NOTARIST',
        object_name   => 'DOKUMEN_LEGAL',
        policy_name   => 'DOKUMEN_LEGAL_TENANT_POLICY'
    );
END;

BEGIN
    DBMS_RLS.DROP_POLICY(
        object_schema => 'NOTARIST',
        object_name   => 'NOTARIST_USER',
        policy_name   => 'NOTARIST_USER_TENANT_POLICY'
    );
END;
